21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const BLOCK_SIZE = 3;
35	const BLOCK_BASE_PREMIUM = 60;
36	
37	const groupBasePremium = (type: string, count: number): number => {
38	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
39	  return count * BASE_PREMIUM[type];
40	};
41	
42	const countByType = (items: Item[]): Map<string, number> =>
43	  items.reduce(
44	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
45	    new Map<string, number>(),
46	  );
47	
48	const policyBase = (items: Item[]): number =>
49	  Array.from(countByType(items)).reduce(
50	    (total, [type, count]) => total + groupBasePremium(type, count),
51	    0,
52	  );
53	
54	const CURSED_RATE = 0.5;
55	const HIGH_ENCHANTMENT_RATE = 0.3;
56	const HIGH_ENCHANTMENT_THRESHOLD = 5;
57	
58	const SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
59	  (item) => (item.cursed ? CURSED_RATE : 0),
60	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0),
61	];
62	
63	const itemSurcharges = (item: Item): number => {
64	  const itemBase = BASE_PREMIUM[item.type];
65	  const totalRate = SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
66	  return itemBase * totalRate;
67	};
68	
69	const policySurcharges = (items: Item[]): number =>
70	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
71	
72	const quoteStep = ({ items }: QuoteStep): QuoteResult => {
73	  const base = policyBase(items);
74	  const surcharges = policySurcharges(items);
75	  const firstInsurance = base * FIRST_INSURANCE_RATE;
76	  return { premium: Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE) };
77	};
78	
79	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
80	  const results = scenario.steps.map(quoteStep);
81	  return { results };
82	};
